// Name the owning container and the pre-state address space once so we can
// reuse them in the bridging asserts below.
let oc = pre_self_.get_proc(target_proc_ptr).owning_container;
let pre_as = pre_self_.get_address_space(target_proc_ptr);

// --- Re-pull the address-space ensures for each run.  Both ensures share
//     the same RHS shape `pre_as.insert(target_va, r_i.1)`, so making them
//     locally available lets z3 line them up across the two runs.
assert(post1_self_.get_address_space(target_proc_ptr)
    =~= pre_as.insert(target_va, r1.1));
assert(post2_self_.get_address_space(target_proc_ptr)
    =~= pre_as.insert(target_va, r2.1));

// Point evaluation at the freshly-inserted key target_va:
// because `target_va` was not in `pre_as.dom()` (precondition) and Map::insert
// places it there, indexing both post-states at `target_va` yields the
// per-run MapEntry r_i.1.
assert(post1_self_.get_address_space(target_proc_ptr).dom().contains(target_va));
assert(post2_self_.get_address_space(target_proc_ptr).dom().contains(target_va));
assert(post1_self_.get_address_space(target_proc_ptr)[target_va] == r1.1);
assert(post2_self_.get_address_space(target_proc_ptr)[target_va] == r2.1);

// --- Re-pull the num_of_free_pages ensures so the arithmetic relating
//     r1.0 and r2.0 is in scope as a ground fact for both runs.
assert(post1_self_.get_num_of_free_pages()
    == pre_self_.get_num_of_free_pages() - r1.0);
assert(post2_self_.get_num_of_free_pages()
    == pre_self_.get_num_of_free_pages() - r2.0);
assert(r1.0 <= 4);
assert(r2.0 <= 4);

// --- Re-pull the quota subtraction relation for each run (lets z3 see the
//     spec_subtract_mem_4k predicate with both r1.0 and r2.0 in scope).
assert(pre_self_.get_container(oc).quota.spec_subtract_mem_4k(
    post1_self_.get_container(oc).quota, r1.0));
assert(pre_self_.get_container(oc).quota.spec_subtract_mem_4k(
    post2_self_.get_container(oc).quota, r2.0));

// --- Re-pull the page-allocator mapping ensures, in particular the
//     "is_mapped" fact on the freshly allocated address and the
//     not-previously-mapped fact for the same address in the pre-state.
assert(pre_self_.page_alloc.page_is_mapped(r1.1.addr) == false);
assert(pre_self_.page_alloc.page_is_mapped(r2.1.addr) == false);
assert(post1_self_.page_alloc.page_is_mapped(r1.1.addr));
assert(post2_self_.page_alloc.page_is_mapped(r2.1.addr));

// --- Re-pull the page_mapping@ ensures, including the singleton at the
//     freshly inserted key.  This grounds the dom-extension and the
//     point-wise value for both runs.
assert(post1_self_.page_mapping@.dom()
    == pre_self_.page_mapping@.dom().insert(r1.1.addr));
assert(post2_self_.page_mapping@.dom()
    == pre_self_.page_mapping@.dom().insert(r2.1.addr));
assert(post1_self_.page_mapping@[r1.1.addr]
    == Set::<(ProcPtr, VAddr)>::empty().insert((target_proc_ptr, target_va)));
assert(post2_self_.page_mapping@[r2.1.addr]
    == Set::<(ProcPtr, VAddr)>::empty().insert((target_proc_ptr, target_va)));

// --- Pull the address-space domain ensures together with the dom-insert
//     identity.  This lets z3 see that both runs grew the same domain
//     `pre_as.dom().insert(target_va)`.
assert(post1_self_.get_address_space(target_proc_ptr).dom()
    =~= pre_as.dom().insert(target_va));
assert(post2_self_.get_address_space(target_proc_ptr).dom()
    =~= pre_as.dom().insert(target_va));
assert(post1_self_.get_address_space(target_proc_ptr).dom()
    =~= post2_self_.get_address_space(target_proc_ptr).dom());

// --- Re-pull the per-key page_mapping equality for the old keys, for both
//     runs, so that the trigger `post_i_self_.page_mapping@[page_ptr]` is
//     instantiated on the same pre-state keys.
assert forall|page_ptr: PagePtr|
    pre_self_.page_mapping@.dom().contains(page_ptr) implies
    pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]
    by {};
assert forall|page_ptr: PagePtr|
    pre_self_.page_mapping@.dom().contains(page_ptr) implies
    pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]
    by {};
